def count_pairs_below(nums, target):
    nums = sorted(nums)
    lo, hi, c = 0, len(nums) - 1, 0
    while lo < hi:
        if nums[lo] + nums[hi] < target:
            c += hi - lo
            lo += 1
        else:
            hi -= 1
    return c

