def climb_no_double2(n):
    from functools import lru_cache

    @lru_cache(None)
    def go(pos, prev_was_two):
        if pos == n:
            return 1
        if pos > n:
            return 0
        total = go(pos + 1, False)
        if not prev_was_two:
            total += go(pos + 2, True)
        return total

    return go(0, False)

